import React from 'react';

import Button from './button';

import classes from './menu.module.css';
import './font.css';

const Menu = (props) => {
    let info = [
        {icon: 'icon-react', text: 'React-приложения', index: 1},
        {icon: 'icon-sphere', text: 'Лэндинговые страницы', index: 2},
        {icon: 'icon-file-text2', text: 'Обо мне', index: 3},
    ];

    const main = {icon: 'icon-arrow-left2', text: 'Главное меню', index: 0};

    if(props.page != 0) {
        info[props.page - 1] = main;
    };

    return (
        <div className={classes.menu}>
            <Button icon={info[0].icon} text={info[0].text} index={info[0].index} clickHandler={props.onChangeComponent}/>
            <Button icon={info[1].icon} text={info[1].text} index={info[1].index} clickHandler={props.onChangeComponent}/>
            <Button icon={info[2].icon} text={info[2].text} index={info[2].index} clickHandler={props.onChangeComponent}/>
        </div>
    );
};

export default Menu;