import React from 'react';

import classes from './react-page.module.css'

const ReactPage = () => {
    return (
        <>
            <h2>React-приложения</h2>
            <div className={classes['react-page']}>
                <a href='react/cafe/index.html'>
                    <div><span className='icon-react'></span></div>
                    Приложение для заказа еды</a>
                <a href='react/expense-tracker/index.html' className={classes.left}>
                    <div><span className='icon-react'></span></div>
                    Счетчик расходов</a>
                <a href='react/contacts/index.html'>
                    <div><span className='icon-react'></span></div>
                    Список юзеров с возможностью открыть личную карточку</a>
                <a href='react/quiz/index.html' className={classes.left}>
                    <div><span className='icon-react'></span></div>
                    Небольшой тест на знание JS</a>
            </div>
        </>
    );
};

export default ReactPage;