import React from 'react';

import classes from './landings.module.css';

import surfImg from '../img/SurfCo.jpg';
import appImg from '../img/AppLab.jpg';
import axitImg from '../img/Axit.jpg';
import mogoImg from '../img/MoGo.jpg';

const Landings = () => {
    return (
        <>
            <h2>Лэндинговые страницы</h2>
            <div className={classes.landings}>
                <a href='sites/1.Surfers/index.html'>
                    <img src={surfImg}/>
                </a>
                <a href='sites/2.AppLab/index.html'>
                    <img src={appImg}/>
                </a>
                <a href='sites/3.Axit/index.html'>
                    <img src={axitImg}/>
                </a>
                <a href='sites/4.MoGo/index.html'>
                    <img src={mogoImg}/>
                </a>
            </div>
        </>
    );
};

export default Landings;